ValidationRule.errorConditionFormula:
AND(
  OR(
    ISBLANK(ExpectedDelivDate__c),
    ExpectedDelivDate__c <= TODAY()
  ),
  OR(
    $RecordType.DeveloperName = "Tubes_RFP",
    $RecordType.DeveloperName = "Wheels_RFP"
  ),
  NOT(
    OR(
      $Profile.Name = "System Administrator",
      $Profile.Name = "ERP Integration Service"
    )
  )
)
